        el.style.setProperty("--aura-wallpaper", absolutizeUrls(value));
        el.classList.remove("aura-wallpaper--aurora");
        if (isApp) el.setAttribute("wallpaper", "custom");
        else el.classList.add("aura-wallpaper");
