        if (Aura.dialog.isolateBackground) shellEl.__auraDrawerRestoreBg = Aura.dialog.isolateBackground(sidebar);
        if (Aura.dialog.trapFocus) shellEl.__auraDrawerUntrap = Aura.dialog.trapFocus(sidebar);
