    /* Make the panel measurable, then place it. */
    el.style.insetInlineStart = Math.round(r.left) + "px";
    el.style.insetBlockStart = Math.round(r.bottom) + "px";
    var box = el.getBoundingClientRect();
    var gap = tokenPx(el, "--aura-shell-flyout-offset");
    var maxLeft = window.innerWidth - box.width - gap;
    var left = Math.min(Math.max(gap, r.left), Math.max(gap, maxLeft));
    var top = r.bottom + gap;
    var maxTop = window.innerHeight - box.height - gap;
    /* If it would overflow the bottom, flip above the toggle. */
    if (top > maxTop) top = Math.max(gap, r.top - box.height - gap);
    el.style.insetInlineStart = Math.round(left) + "px";
    el.style.insetBlockStart = Math.round(top) + "px";
