    if (shell.isOpen(shellEl)) return;
    cancelClose();
    var el = ensureFlyoutEl();
    if (!populateFlyout(el, sidebar)) return;   // nothing to show
    flyout.toggleEl = tgl;
    el.hidden = false;
    positionFlyout(el, tgl);
    /* Establish the hidden start state, then flip to open so the opacity/scale
       transition runs. A forced reflow (reading offsetWidth) commits the
       initial styles synchronously, so adding the class on the next tick always
       animates — more reliable than rAF when the tab is throttled/backgrounded
       (e.g. headless rendering), where rAF callbacks can stall. */
    /* eslint-disable-next-line no-unused-expressions */
