    menuFallbackLabel:     "Menu",
    newBadge:              "New",
    unpinPanel:            "Unpin panel",
    toggleNavigationPin:   "Toggle navigation pin",
    preview:               "Preview",
    /* shortcut overlay */
    keyboardShortcuts:     "Keyboard shortcuts",
    closeShortcutGuide:    "Close shortcut guide",
    shortcutGuide:         "Show this shortcut guide",
    shortcutNavigate:      "Navigate menu items",
    shortcutActivate:      "Activate focused item",
    shortcutClose:         "Close menu / overlay",
    shortcutBack:          "Close deepest open panel",
    shortcutCycle:         "Cycle focus within panel",
    shortcutSearch:        "Focus panel search bar",
    shortcutOpenSearch:    "Open + focus panel search",
    shortcutJump:          "Jump to first / last item",
    /* overflow menu */
    moreNavigationItems:   "More navigation items",
    moreItemsCount:        "{n} more navigation items",
    more:                  "More",
    /* panel search */
