    itemsFallback:         "items",
    noResults:             "No results",
    /* global search overlay */
    globalSiteSearch:      "Global site search",
    searchPlaceholder:     "Search\u2026",
    searchSite:            "Search site",
    closeSearch:           "Close search",
    escKey:                "Esc",
    searchScope:           "Search scope",
    scopeAll:              "All",
    scopePages:            "Pages",
    scopeComponents:       "Components",
    scopeThemes:           "Themes",
    suggestions:           "Suggestions",
    hintNavigate:          "navigate",
    hintOpen:              "open",
    hintClose:             "close",
    /* breadcrumb back */
    goBack:                "Go back",
    back:                  "Back",
    /* customize panel */
    customizeNavigation:   "Customize navigation",
    navigationPreferences: "Navigation preferences",
    navigationTitle:       "Navigation",
    compactMode:           "Compact mode",
    hideLabels:            "Hide labels",
    progressBar:           "Progress bar",
    /* group collapse */
    groupToggle:           "{group} group, toggle",
    collapseAllGroups:     "Collapse all groups",
    collapseAll:           "Collapse all",
    expandAll:             "Expand all",
    /* a11y announcements */
    panelAnnouncement:     "{name} navigation menu",
    navMenuRoleDescription:"navigation menu",
    navigationFallbackName:"Navigation",
    /* extras module (js/nav-header-extras.js) — one shared table */
