    noPagesYet:            "No pages yet",
    browseToGetStarted:    "Browse to get started",
    copyLink:              "Copy link",
    copied:                "Copied!",
    sortAZ:                "A\u2013Z",
    sortRecent:            "Recent",
    sortLabel:             "Sort {label}",
    accentColorPicker:     "Accent color picker",
    chooseAccentColor:     "Choose accent color",
    accentIndigo:          "Indigo",
    accentViolet:          "Violet",
    accentEmerald:         "Emerald",
