    if (_announceTimer !== null)     { clearTimeout(_announceTimer);     _announceTimer = null; }
    if (focusBeaconTimer !== null)   { clearTimeout(focusBeaconTimer);   focusBeaconTimer = null; }
    navHasFocus = false;
    if (_navWidePanelTimer !== null) { clearTimeout(_navWidePanelTimer); _navWidePanelTimer = null; }
