    title.id = titleId;
    title.setAttribute("style",
      "position:absolute;inline-size:1px;block-size:1px;overflow:hidden;clip:rect(0,0,0,0);white-space:nowrap");
    title.textContent = navStr("globalSiteSearch");
    overlay.appendChild(title);

